"use strict";(self.webpackChunkwangdoc=self.webpackChunkwangdoc||[]).push([[2671],{57696:(e,n,a)=>{a.r(n),a.d(n,{data:()=>s});const s={key:"v-66fd0f0a",path:"/webapi-tutorial/page-lifecycle.html",title:"Page Lifecycle API",lang:"zh-CN",frontmatter:{summary:"Page Lifecycle API Android、iOS 和最新的 Windows 系统可以随时自主地停止后台进程，及时释放系统资源。也就是说，网页可能随时被系统丢弃掉。以前的浏览器 API 完全没有考虑到这种情况，导致开发者根本没有办法监听到系统丢弃页面。 为了解决这个问题，W3C 新制定了一个 Page Lifecycle API，统一了网页从诞生到",head:[["meta",{property:"og:url",content:"https://yzqbooks.github.io/wangdoc/wangdoc/webapi-tutorial/page-lifecycle.html"}],["meta",{property:"og:site_name",content:"wangdoc"}],["meta",{property:"og:title",content:"Page Lifecycle API"}],["meta",{property:"og:type",content:"article"}],["meta",{property:"og:updated_time",content:"2022-04-06T10:09:00.000Z"}],["meta",{property:"og:locale",content:"zh-CN"}],["meta",{property:"article:modified_time",content:"2022-04-06T10:09:00.000Z"}]]},excerpt:"",headers:[{level:2,title:"生命周期阶段",slug:"生命周期阶段",children:[]},{level:2,title:"常见场景",slug:"常见场景",children:[]},{level:2,title:"事件",slug:"事件",children:[{level:3,title:"focus 事件",slug:"focus-事件",children:[]},{level:3,title:"blur 事件",slug:"blur-事件",children:[]},{level:3,title:"visibilitychange 事件",slug:"visibilitychange-事件",children:[]},{level:3,title:"freeze 事件",slug:"freeze-事件",children:[]},{level:3,title:"resume 事件",slug:"resume-事件",children:[]},{level:3,title:"pageshow 事件",slug:"pageshow-事件",children:[]},{level:3,title:"pagehide 事件",slug:"pagehide-事件",children:[]},{level:3,title:"beforeunload 事件",slug:"beforeunload-事件",children:[]},{level:3,title:"unload 事件",slug:"unload-事件",children:[]}]},{level:2,title:"获取当前阶段",slug:"获取当前阶段",children:[]},{level:2,title:"document.wasDiscarded",slug:"document-wasdiscarded",children:[]},{level:2,title:"参考链接",slug:"参考链接",children:[]}],git:{createdTime:164923974e4,updatedTime:164923974e4,contributors:[{name:"yzqdev",email:"yzqdev@outlook.com",commits:1}]},readingTime:{minutes:7.22,words:2167},filePathRelative:"webapi-tutorial/page-lifecycle.md"}},5541:(e,n,a)=>{a.r(n),a.d(n,{default:()=>z});var s=a(66252);const t=(0,s._)("h1",{id:"page-lifecycle-api",tabindex:"-1"},[(0,s._)("a",{class:"header-anchor",href:"#page-lifecycle-api","aria-hidden":"true"},"#"),(0,s.Uk)(" Page Lifecycle API")],-1),p=(0,s._)("p",null,"Android、iOS 和最新的 Windows 系统可以随时自主地停止后台进程，及时释放系统资源。也就是说，网页可能随时被系统丢弃掉。以前的浏览器 API 完全没有考虑到这种情况，导致开发者根本没有办法监听到系统丢弃页面。",-1),c=(0,s._)("p",null,"为了解决这个问题，W3C 新制定了一个 Page Lifecycle API，统一了网页从诞生到卸载的行为模式，并且定义了新的事件，允许开发者响应网页状态的各种转换。",-1),o=(0,s.Uk)("有了这个 API，开发者就可以预测网页下一步的状态，从而进行各种针对性的处理。Chrome 68 支持这个 API，对于老式浏览器可以使用谷歌开发的兼容库 "),i={href:"https://github.com/GoogleChromeLabs/page-lifecycle",target:"_blank",rel:"noopener noreferrer"},r=(0,s.Uk)("PageLifecycle.js"),l=(0,s.Uk)("。"),d=(0,s.uE)('<h2 id="生命周期阶段" tabindex="-1"><a class="header-anchor" href="#生命周期阶段" aria-hidden="true">#</a> 生命周期阶段</h2><p>网页的生命周期分成六个阶段，每个时刻只可能处于其中一个阶段。</p><p><img src="https://www.wangbase.com/blogimg/asset/201811/bg2018110401.png" alt="" loading="lazy"></p><p><strong>（1）Active 阶段</strong></p><p>在 Active 阶段，网页处于可见状态，且拥有输入焦点。</p><p><strong>（2）Passive 阶段</strong></p><p>在 Passive 阶段，网页可见，但没有输入焦点，无法接受输入。UI 更新（比如动画）仍然在执行。该阶段只可能发生在桌面同时有多个窗口的情况。</p><p><strong>（3）Hidden 阶段</strong></p><p>在 Hidden 阶段，用户的桌面被其他窗口占据，网页不可见，但尚未冻结。UI 更新不再执行。</p><p><strong>（4）Terminated 阶段</strong></p><p>在 Terminated 阶段，由于用户主动关闭窗口，或者在同一个窗口前往其他页面，导致当前页面开始被浏览器卸载并从内存中清除。注意，这个阶段总是在 Hidden 阶段之后发生，也就是说，用户主动离开当前页面，总是先进入 Hidden 阶段，再进入 Terminated 阶段。</p><p>这个阶段会导致网页卸载，任何新任务都不会在这个阶段启动，并且如果运行时间太长，正在进行的任务可能会被终止。</p><p><strong>（5）Frozen 阶段</strong></p><p>如果网页处于 Hidden 阶段的时间过久，用户又不关闭网页，浏览器就有可能冻结网页，使其进入 Frozen 阶段。不过，也有可能，处于可见状态的页面长时间没有操作，也会进入 Frozen 阶段。</p><p>这个阶段的特征是，网页不会再被分配 CPU 计算资源。定时器、回调函数、网络请求、DOM 操作都不会执行，不过正在运行的任务会执行完。浏览器可能会允许 Frozen 阶段的页面，周期性复苏一小段时间，短暂变回 Hidden 状态，允许一小部分任务执行。</p><p><strong>（6）Discarded 阶段</strong></p><p>如果网页长时间处于 Frozen 阶段，用户又不唤醒页面，那么就会进入 Discarded 阶段，即浏览器自动卸载网页，清除该网页的内存占用。不过，Passive 阶段的网页如果长时间没有互动，也可能直接进入 Discarded 阶段。</p><p>这一般是在用户没有介入的情况下，由系统强制执行。任何类型的新任务或 JavaScript 代码，都不能在此阶段执行，因为这时通常处在资源限制的状况下。</p><p>网页被浏览器自动 Discarded 以后，它的 Tab 窗口还是在的。如果用户重新访问这个 Tab 页，浏览器将会重新向服务器发出请求，再一次重新加载网页，回到 Active 阶段。</p><h2 id="常见场景" tabindex="-1"><a class="header-anchor" href="#常见场景" aria-hidden="true">#</a> 常见场景</h2><p>以下是几个常见场景的网页生命周期变化。</p><p>（1）用户打开网页后，又切换到其他 App，但只过了一会又回到网页。</p><p>网页由 Active 变成 Hidden，又变回 Active。</p><p>（2）用户打开网页后，又切换到其他 App，并且长时候使用后者，导致系统自动丢弃网页。</p><p>网页由 Active 变成 Hidden，再变成 Frozen，最后 Discarded。</p><p>（3）用户打开网页后，又切换到其他 App，然后从任务管理器里面将浏览器进程清除。</p><p>网页由 Active 变成 Hidden，然后 Terminated。</p><p>（4）系统丢弃了某个 Tab 里面的页面后，用户重新打开这个 Tab。</p><p>网页由 Discarded 变成 Active。</p><h2 id="事件" tabindex="-1"><a class="header-anchor" href="#事件" aria-hidden="true">#</a> 事件</h2><p>生命周期的各个阶段都有自己的事件，以供开发者指定监听函数。这些事件里面，只有两个是新定义的（<code>freeze</code>事件和<code>resume</code>事件），其它都是现有的。</p><p>注意，网页的生命周期事件是在所有帧（frame）触发，不管是底层的帧，还是内嵌的帧。也就是说，内嵌的<code>&lt;iframe&gt;</code>网页跟顶层网页一样，都会同时监听到下面的事件。</p><h3 id="focus-事件" tabindex="-1"><a class="header-anchor" href="#focus-事件" aria-hidden="true">#</a> focus 事件</h3><p><code>focus</code>事件在页面获得输入焦点时触发，比如网页从 Passive 阶段变为 Active 阶段。</p><h3 id="blur-事件" tabindex="-1"><a class="header-anchor" href="#blur-事件" aria-hidden="true">#</a> blur 事件</h3><p><code>blur</code>事件在页面失去输入焦点时触发，比如网页从 Active 阶段变为 Passive 阶段。</p><h3 id="visibilitychange-事件" tabindex="-1"><a class="header-anchor" href="#visibilitychange-事件" aria-hidden="true">#</a> visibilitychange 事件</h3><p><code>visibilitychange</code>事件在网页可见状态发生变化时触发，一般发生在以下几种场景。</p><blockquote><ul><li>用户隐藏页面（切换 Tab、最小化浏览器），页面由 Active 阶段变成 Hidden 阶段。</li><li>用户重新访问隐藏的页面，页面由 Hidden 阶段变成 Active 阶段。</li><li>用户关闭页面，页面会先进入 Hidden 阶段，然后进入 Terminated 阶段。</li></ul></blockquote><p>可以通过<code>document.onvisibilitychange</code>属性指定这个事件的回调函数。</p><h3 id="freeze-事件" tabindex="-1"><a class="header-anchor" href="#freeze-事件" aria-hidden="true">#</a> freeze 事件</h3><p><code>freeze</code>事件在网页进入 Frozen 阶段时触发。</p><p>可以通过<code>document.onfreeze</code>属性指定在进入 Frozen 阶段时调用的回调函数。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">handleFreeze</span><span class="token punctuation">(</span><span class="token parameter">e</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token comment">// Handle transition to FROZEN</span>\n<span class="token punctuation">}</span>\ndocument<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token string">&#39;freeze&#39;</span><span class="token punctuation">,</span> handleFreeze<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n# 或者\ndocument<span class="token punctuation">.</span><span class="token function-variable function">onfreeze</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> … <span class="token punctuation">}</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>这个事件的监听函数，最长只能运行500毫秒。并且只能复用已经打开的网络连接，不能发起新的网络请求。</p><p>注意，从 Frozen 阶段进入 Discarded 阶段，不会触发任何事件，无法指定回调函数，只能在进入 Frozen 阶段时指定回调函数。</p><h3 id="resume-事件" tabindex="-1"><a class="header-anchor" href="#resume-事件" aria-hidden="true">#</a> resume 事件</h3><p><code>resume</code>事件在网页离开 Frozen 阶段，变为 Active / Passive / Hidden 阶段时触发。</p><p><code>document.onresume</code>属性指的是页面离开 Frozen 阶段、进入可用状态时调用的回调函数。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">function</span> <span class="token function">handleResume</span><span class="token punctuation">(</span><span class="token parameter">e</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token comment">// handle state transition FROZEN -&gt; ACTIVE</span>\n<span class="token punctuation">}</span>\ndocument<span class="token punctuation">.</span><span class="token function">addEventListener</span><span class="token punctuation">(</span><span class="token string">&quot;resume&quot;</span><span class="token punctuation">,</span> handleResume<span class="token punctuation">)</span><span class="token punctuation">;</span>\n\n# 或者\ndocument<span class="token punctuation">.</span><span class="token function-variable function">onresume</span> <span class="token operator">=</span> <span class="token keyword">function</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span> … <span class="token punctuation">}</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h3 id="pageshow-事件" tabindex="-1"><a class="header-anchor" href="#pageshow-事件" aria-hidden="true">#</a> pageshow 事件</h3><p><code>pageshow</code>事件在用户加载网页时触发。这时，有可能是全新的页面加载，也可能是从缓存中获取的页面。如果是从缓存中获取，则该事件对象的<code>event.persisted</code>属性为<code>true</code>，否则为<code>false</code>。</p><p>这个事件的名字有点误导，它跟页面的可见性其实毫无关系，只跟浏览器的 History 记录的变化有关。</p><h3 id="pagehide-事件" tabindex="-1"><a class="header-anchor" href="#pagehide-事件" aria-hidden="true">#</a> pagehide 事件</h3><p><code>pagehide</code>事件在用户离开当前网页、进入另一个网页时触发。它的前提是浏览器的 History 记录必须发生变化，跟网页是否可见无关。</p><p>如果浏览器能够将当前页面添加到缓存以供稍后重用，则事件对象的<code>event.persisted</code>属性为<code>true</code>。 如果为<code>true</code>。如果页面添加到了缓存，则页面进入 Frozen 状态，否则进入 Terminatied 状态。</p><h3 id="beforeunload-事件" tabindex="-1"><a class="header-anchor" href="#beforeunload-事件" aria-hidden="true">#</a> beforeunload 事件</h3><p><code>beforeunload</code>事件在窗口或文档即将卸载时触发。该事件发生时，文档仍然可见，此时卸载仍可取消。经过这个事件，网页进入 Terminated 状态。</p><h3 id="unload-事件" tabindex="-1"><a class="header-anchor" href="#unload-事件" aria-hidden="true">#</a> unload 事件</h3><p><code>unload</code>事件在页面正在卸载时触发。经过这个事件，网页进入 Terminated 状态。</p><h2 id="获取当前阶段" tabindex="-1"><a class="header-anchor" href="#获取当前阶段" aria-hidden="true">#</a> 获取当前阶段</h2><p>如果网页处于 Active、Passive 或 Hidden 阶段，可以通过下面的代码，获得网页当前的状态。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">const</span> <span class="token function-variable function">getState</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n  <span class="token keyword">if</span> <span class="token punctuation">(</span>document<span class="token punctuation">.</span>visibilityState <span class="token operator">===</span> <span class="token string">&#39;hidden&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> <span class="token string">&#39;hidden&#39;</span><span class="token punctuation">;</span>\n  <span class="token punctuation">}</span>\n  <span class="token keyword">if</span> <span class="token punctuation">(</span>document<span class="token punctuation">.</span><span class="token function">hasFocus</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">return</span> <span class="token string">&#39;active&#39;</span><span class="token punctuation">;</span>\n  <span class="token punctuation">}</span>\n  <span class="token keyword">return</span> <span class="token string">&#39;passive&#39;</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>如果网页处于 Frozen 和 Terminated 状态，由于定时器代码不会执行，只能通过事件监听判断状态。进入 Frozen 阶段，可以监听<code>freeze</code>事件；进入 Terminated 阶段，可以监听<code>pagehide</code>事件。</p><h2 id="document-wasdiscarded" tabindex="-1"><a class="header-anchor" href="#document-wasdiscarded" aria-hidden="true">#</a> document.wasDiscarded</h2><p>如果某个选项卡处于 Frozen 阶段，就随时有可能被系统丢弃，进入 Discarded 阶段。如果后来用户再次点击该选项卡，浏览器会重新加载该页面。</p><p>这时，开发者可以通过判断<code>document.wasDiscarded</code>属性，了解先前的网页是否被丢弃了。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token keyword">if</span> <span class="token punctuation">(</span>document<span class="token punctuation">.</span>wasDiscarded<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n  <span class="token comment">// 该网页已经不是原来的状态了，曾经被浏览器丢弃过</span>\n  <span class="token comment">// 恢复以前的状态</span>\n  <span class="token function">getPersistedState</span><span class="token punctuation">(</span>self<span class="token punctuation">.</span>discardedClientId<span class="token punctuation">)</span><span class="token punctuation">;</span>\n<span class="token punctuation">}</span>\n</code></pre><div class="line-numbers" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>同时，<code>window</code>对象上会新增<code>window.clientId</code>和<code>window.discardedClientId</code>两个属性，用来恢复丢弃前的状态。</p><h2 id="参考链接" tabindex="-1"><a class="header-anchor" href="#参考链接" aria-hidden="true">#</a> 参考链接</h2>',70),u={href:"https://developers.google.com/web/updates/2018/07/page-lifecycle-api",target:"_blank",rel:"noopener noreferrer"},h=(0,s.Uk)("Page Lifecycle API"),b=(0,s.Uk)(", Philip Walton"),k={href:"https://github.com/WICG/page-lifecycle",target:"_blank",rel:"noopener noreferrer"},m=(0,s.Uk)("Lifecycle API for Web Pages"),g=(0,s.Uk)(", W3C"),f={href:"https://wicg.github.io/page-lifecycle/spec.html",target:"_blank",rel:"noopener noreferrer"},v=(0,s.Uk)("Page Lifecycle 1 Editor’s Draft"),y=(0,s.Uk)(", W3C"),w={},z=(0,a(83744).Z)(w,[["render",function(e,n){const a=(0,s.up)("ExternalLinkIcon");return(0,s.wg)(),(0,s.iD)(s.HY,null,[t,p,c,(0,s._)("p",null,[o,(0,s._)("a",i,[r,(0,s.Wm)(a)]),l]),d,(0,s._)("ul",null,[(0,s._)("li",null,[(0,s._)("a",u,[h,(0,s.Wm)(a)]),b]),(0,s._)("li",null,[(0,s._)("a",k,[m,(0,s.Wm)(a)]),g]),(0,s._)("li",null,[(0,s._)("a",f,[v,(0,s.Wm)(a)]),y])])],64)}]])},83744:(e,n)=>{n.Z=(e,n)=>{const a=e.__vccOpts||e;for(const[e,s]of n)a[e]=s;return a}}}]);